namespace Payments;

/// <summary>
/// Abstraction over a third-party payment provider (Stripe, Braintree, etc.).
/// </summary>
public interface IPaymentProvider
{
    Task<ProviderChargeResponse> ChargeAsync(string cardToken, decimal amount);
    Task<ProviderRefundResponse> RefundAsync(string chargeId);
}

public record ProviderChargeResponse(string ChargeId, bool Success, string? ErrorMessage = null);
public record ProviderRefundResponse(string RefundId, bool Success, string? ErrorMessage = null);

public sealed class PaymentGateway
{
    private const decimal MaxChargeAmount = 999_999.99m;

    private readonly IPaymentProvider _provider;

    public PaymentGateway(IPaymentProvider provider)
    {
        _provider = provider ?? throw new ArgumentNullException(nameof(provider));
    }

    public async Task<ChargeResult> ChargeAsync(string cardToken, decimal amount)
    {
        if (string.IsNullOrWhiteSpace(cardToken))
            throw new ArgumentException("Card token is required.", nameof(cardToken));
        if (amount <= 0)
            throw new ArgumentOutOfRangeException(nameof(amount), "Amount must be positive.");
        if (amount > MaxChargeAmount)
            throw new ArgumentOutOfRangeException(nameof(amount), "Amount exceeds maximum allowed.");

        var response = await _provider.ChargeAsync(cardToken, amount);
        return new ChargeResult(response.ChargeId, response.Success, response.ErrorMessage);
    }

    public async Task<RefundResult> RefundAsync(string chargeId)
    {
        if (string.IsNullOrWhiteSpace(chargeId))
            throw new ArgumentException("Charge ID is required.", nameof(chargeId));

        var response = await _provider.RefundAsync(chargeId);
        return new RefundResult(response.RefundId, response.Success, response.ErrorMessage);
    }

    public WebhookResult ProcessWebhook(string eventType, string payload)
    {
        if (string.IsNullOrWhiteSpace(eventType))
            throw new ArgumentException("Event type is required.", nameof(eventType));
        if (string.IsNullOrWhiteSpace(payload))
            throw new ArgumentException("Payload is required.", nameof(payload));

        var status = eventType switch
        {
            "charge.succeeded" => WebhookStatus.Succeeded,
            "charge.failed" => WebhookStatus.Failed,
            "refund.succeeded" => WebhookStatus.Succeeded,
            "refund.failed" => WebhookStatus.Failed,
            _ => WebhookStatus.Unknown,
        };

        return new WebhookResult(eventType, status);
    }
}

public record ChargeResult(string ChargeId, bool Success, string? ErrorMessage = null);
public record RefundResult(string RefundId, bool Success, string? ErrorMessage = null);
public record WebhookResult(string EventType, WebhookStatus Status);

public enum WebhookStatus
{
    Unknown,
    Succeeded,
    Failed,
}

