using Moq;
using Payments;

namespace PaymentGateway.Tests;

[TestClass]
public class PaymentGatewayConstructorTests
{
    [TestMethod]
    public void Constructor_NullProvider_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => new Payments.PaymentGateway(null!));
    }

    [TestMethod]
    public void Constructor_ValidProvider_DoesNotThrow()
    {
        var provider = new Mock<IPaymentProvider>();
        var gateway = new Payments.PaymentGateway(provider.Object);
        Assert.IsNotNull(gateway);
    }
}

[TestClass]
public class ChargeAsyncTests
{
    private Mock<IPaymentProvider> _providerMock = null!;
    private Payments.PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _providerMock = new Mock<IPaymentProvider>();
        _gateway = new Payments.PaymentGateway(_providerMock.Object);
    }

    // --- Validation tests ---

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_InvalidCardToken_ThrowsArgumentException(string? token)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(token!, 10m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    [DataRow(-0.01)]
    public async Task ChargeAsync_NonPositiveAmount_ThrowsArgumentOutOfRangeException(double amount)
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_valid", (decimal)amount));
    }

    [TestMethod]
    public async Task ChargeAsync_AmountExceedsMax_ThrowsArgumentOutOfRangeException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_valid", 1_000_000m));
    }

    [TestMethod]
    public async Task ChargeAsync_AmountAtMax_Succeeds()
    {
        _providerMock
            .Setup(p => p.ChargeAsync("tok_valid", 999_999.99m))
            .ReturnsAsync(new ProviderChargeResponse("ch_1", true));

        var result = await _gateway.ChargeAsync("tok_valid", 999_999.99m);

        Assert.IsTrue(result.Success);
    }

    // --- Happy-path tests ---

    [TestMethod]
    public async Task ChargeAsync_SuccessfulCharge_ReturnsSuccessResult()
    {
        _providerMock
            .Setup(p => p.ChargeAsync("tok_abc", 49.99m))
            .ReturnsAsync(new ProviderChargeResponse("ch_123", true));

        var result = await _gateway.ChargeAsync("tok_abc", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.AreEqual("ch_123", result.ChargeId);
        Assert.IsNull(result.ErrorMessage);
    }

    [TestMethod]
    public async Task ChargeAsync_FailedCharge_ReturnsFailureWithError()
    {
        _providerMock
            .Setup(p => p.ChargeAsync("tok_bad", 10m))
            .ReturnsAsync(new ProviderChargeResponse("ch_fail", false, "Card declined"));

        var result = await _gateway.ChargeAsync("tok_bad", 10m);

        Assert.IsFalse(result.Success);
        Assert.AreEqual("Card declined", result.ErrorMessage);
    }

    [TestMethod]
    public async Task ChargeAsync_ProviderThrows_ExceptionPropagates()
    {
        _providerMock
            .Setup(p => p.ChargeAsync(It.IsAny<string>(), It.IsAny<decimal>()))
            .ThrowsAsync(new InvalidOperationException("Provider unavailable"));

        await Assert.ThrowsExceptionAsync<InvalidOperationException>(
            () => _gateway.ChargeAsync("tok_abc", 25m));
    }

    [TestMethod]
    public async Task ChargeAsync_ValidatesBeforeCallingProvider()
    {
        // Passing an invalid token should throw without ever hitting the provider.
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("", 10m));

        _providerMock.Verify(
            p => p.ChargeAsync(It.IsAny<string>(), It.IsAny<decimal>()),
            Times.Never);
    }

    [TestMethod]
    public async Task ChargeAsync_SmallAmount_Succeeds()
    {
